}

void solve() {
    scanf("%d %d", &N, &M);
    for (int i = 1; i <= N; i++) {
        for (int j = 0; j < MAXC; j++) {
            for (int k = 0; k < MAXC; k++) {
                scanf(" %c", &cakes[i][j][k]);
                cakes[i][j][k] -= '0';
            }
        }
        grundy[i] = getGrundy(cakes[i]);
        update(i, grundy[i]);
    }
    for (int i = 1; i <= M; i++) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int L, R;
            scanf("%d %d", &L, &R);
            int res = query(R) ^ query(L - 1);
            if (res > 0) {
                printf("Pishty\n");
            } else {
                printf("Lotsy\n");
            }
        } else {
            int pos;
            scanf("%d", &pos);
            for (int j = 0; j < MAXC; j++) {
                for (int k = 0; k < MAXC; k++) {
